import java.util.*;
import java.util.stream.*;

public class Main {

    public static void main(String[] args) {
        Scanner input = new Scanner(System.in);
        int n = input.nextInt();
        long total = 0;
        for (int value = 1; value <= n; value++) total += value;
        System.out.println(total);
    }
}
